import{_ as t,c as o,o as n,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.65: Tool Definition Hook","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.65.md","filePath":"en/changelog/v1.1.65.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.65.md"};function s(l,a,d,h,c,p){return n(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-65-tool-definition-hook" tabindex="-1">v1.1.65: Tool Definition Hook <a class="header-anchor" href="#v1-1-65-tool-definition-hook" aria-label="Permalink to ‚Äúv1.1.65: Tool Definition Hook‚Äù">‚Äã</a></h1><p><strong>Release Date</strong>: February 13, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to ‚ÄúOne-Sentence Summary‚Äù">‚Äã</a></h2><p>This update adds <strong>tool.definition Hook</strong> for plugins to modify tool descriptions and parameters, and fixes Windows ACP freeze, multiple desktop issues.</p><hr><h2 id="new-feature-tool-definition-hook" tabindex="-1">New Feature: Tool Definition Hook <a class="header-anchor" href="#new-feature-tool-definition-hook" aria-label="Permalink to ‚ÄúNew Feature: Tool Definition Hook‚Äù">‚Äã</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to ‚ÄúWhat&#39;s Updated?‚Äù">‚Äã</a></h3><p>Plugins can now use <strong>tool.definition Hook</strong> to modify tool descriptions and parameters.</p><h3 id="what-is-this" tabindex="-1">What is This? <a class="header-anchor" href="#what-is-this" aria-label="Permalink to ‚ÄúWhat is This?‚Äù">‚Äã</a></h3><p>Hooks are plugin extension points. Through this new Hook, plugins can:</p><ul><li>Modify tool description text</li><li>Adjust tool parameter definitions</li><li>Customize tool display</li></ul><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to ‚ÄúUse Cases‚Äù">‚Äã</a></h3><ul><li>Add custom hints for specific tools</li><li>Hide unneeded tool parameters</li><li>Adjust tool default behavior descriptions</li></ul><hr><h2 id="improvement-directory-uses-read-tool" tabindex="-1">Improvement: @directory Uses Read Tool <a class="header-anchor" href="#improvement-directory-uses-read-tool" aria-label="Permalink to ‚ÄúImprovement: @directory Uses Read Tool‚Äù">‚Äã</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to ‚ÄúWhat&#39;s Updated?‚Äù">‚Äã</a></h3><p>When you @ a directory in conversation, OpenCode now uses <strong>Read tool instead of deprecated List tool</strong>.</p><h3 id="what-are-the-benefits" tabindex="-1">What are the Benefits? <a class="header-anchor" href="#what-are-the-benefits" aria-label="Permalink to ‚ÄúWhat are the Benefits?‚Äù">‚Äã</a></h3><ul><li>Get more complete directory information</li><li>More consistent behavior</li><li>Preparation for future List tool removal</li></ul><hr><h2 id="bug-fix-windows-acp-freeze" tabindex="-1">Bug Fix: Windows ACP Freeze <a class="header-anchor" href="#bug-fix-windows-acp-freeze" aria-label="Permalink to ‚ÄúBug Fix: Windows ACP Freeze‚Äù">‚Äã</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to ‚ÄúPrevious Issue‚Äù">‚Äã</a></h3><p>On Windows, ACP (Agent Communication Protocol) would sometimes indefinitely get stuck in thinking state.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to ‚ÄúCurrent Status‚Äù">‚Äã</a></h3><p>Fixed this issue, no more freezing on Windows.</p><hr><h2 id="improvement-desktop" tabindex="-1">Improvement: Desktop <a class="header-anchor" href="#improvement-desktop" aria-label="Permalink to ‚ÄúImprovement: Desktop‚Äù">‚Äã</a></h2><h3 id="event-stream-reconnection" tabindex="-1">Event Stream Reconnection <a class="header-anchor" href="#event-stream-reconnection" aria-label="Permalink to ‚ÄúEvent Stream Reconnection‚Äù">‚Äã</a></h3><p>Desktop app automatically reconnects event stream after disconnection, more stable.</p><h3 id="batch-model-switching" tabindex="-1">Batch Model Switching <a class="header-anchor" href="#batch-model-switching" aria-label="Permalink to ‚ÄúBatch Model Switching‚Äù">‚Äã</a></h3><p>In settings you can <strong>switch models for all providers at once</strong>, no need to switch one by one.</p><h3 id="loading-page-optimization" tabindex="-1">Loading Page Optimization <a class="header-anchor" href="#loading-page-optimization" aria-label="Permalink to ‚ÄúLoading Page Optimization‚Äù">‚Äã</a></h3><p>Optimized desktop loading page, only shows loading window when SQLite migration is needed.</p><h3 id="notification-navigation" tabindex="-1">Notification Navigation <a class="header-anchor" href="#notification-navigation" aria-label="Permalink to ‚ÄúNotification Navigation‚Äù">‚Äã</a></h3><p>Clicking notifications navigates directly to the corresponding session.</p><h3 id="input-box-fix" tabindex="-1">Input Box Fix <a class="header-anchor" href="#input-box-fix" aria-label="Permalink to ‚ÄúInput Box Fix‚Äù">‚Äã</a></h3><p>Fixed some prompt input box behavior issues.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to ‚ÄúShould You Upgrade?‚Äù">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Developing plugins</td><td>‚úÖ Upgrade</td></tr><tr><td>Windows users</td><td>‚úÖ Highly Recommended</td></tr><tr><td>Using desktop version</td><td>‚úÖ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',42),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to ‚ÄúTechnical Details (Skippable)‚Äù">‚Äã</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to ‚ÄúCore‚Äù">‚Äã</a></h3><ul><li>Revert token replacement in OPENCODE_CONFIG_CONTENT</li><li>@directory uses Read tool instead of deprecated List tool</li><li>Add tool.definition Hook, allow plugins to modify tool descriptions and parameters</li><li>Remove worktree delete functionality</li><li>Resolve issue where ACP indefinitely stuck in thinking state on Windows</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to ‚ÄúDesktop‚Äù">‚Äã</a></h3><ul><li>Reconnect event stream on disconnect</li><li>Batch switch all provider models in settings</li><li>Clean up desktop loading page</li><li>Notification click navigates to session</li><li>Fix prompt input box behavior issues</li><li>Fix store creation failure in app</li><li>Only show loading window when SQLite migration is needed</li></ul><h3 id="community-contributions" tabindex="-1">Community Contributions <a class="header-anchor" href="#community-contributions" aria-label="Permalink to ‚ÄúCommunity Contributions‚Äù">‚Äã</a></h3><ul><li>@spoons-and-mirrors: Add tool.definition Hook</li><li>@ASidorenkoCode: Fix Windows ACP freeze issue</li><li>@Brendonovich: Multiple desktop optimizations (loading page, SQLite migration detection)</li></ul></details><hr><p><a href="./">‚Üê Back to Changelog</a></p>',5)])])}const f=t(r,[["render",s]]);export{m as __pageData,f as default};
